  ('heelevel3-6f0ba476-moex-00253', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '在競爭性的勞動市場上，勞動供給曲線為後彎形狀（backward-bendingsupplyschedule），需求曲線 為負斜率。在勞動供給曲線後彎區段，政府課徵定額（specific）工資稅，將造成工資率降低幅度 較定額工資稅額為：', '["大", "相等", "小", "無法比較"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00254', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '假設政府對廠商的經濟利潤課稅，對利潤極大化廠商而言，下列敘述何者正確？', '["部分稅負可轉嫁給消費者", "稅負無法轉嫁", "廠商減少產量來保障利潤", "廠商會增加產量來保障利潤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00255', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '對完全競爭市場中的某項商品課徵貨物稅，且假設稽徵成本與順從成本均為0。下列敘述何者正 確？', '["使生產者為法定納稅義務人之稅收大於使消費者為法定納稅義務人之稅收", "使生產者為法定納稅義務人之稅收小於使消費者為法定納稅義務人之稅收", "稅收相同情況下，從量課稅與從價課稅之經濟效果相同", "法律歸宿必等於經濟歸宿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00256', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '財貨A為完全競爭市場，受補償需求的價格彈性絕對值為0.2，供給曲線為一水平線。假設政府對 財貨A課徵單位稅額為10元的從量稅，稅前均衡價格為100元，受補償需求量為200，課稅後產生 的超額負擔為多少？', '["5元", "20元", "2,000元", "200,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00257', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '乒乓球與乒乓球拍為互補品，假設此兩財貨的供給曲線皆為水平線，需求曲線則為負斜率。若政 府原本只對乒乓球課稅，現若開始對乒乓球拍課稅，則根據次佳理論，對乒乓球與乒乓球拍課稅 的超額負擔比只對乒乓球課稅的超額負擔：', '["必然增加", "必然降低", "可能降低", "必然不變"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00258', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '若商品經課稅後之未受補償反應（uncompensatedresponse）為零，下列敘述何者正確？', '["沒有替代效果", "沒有所得效果", "仍會產生超額負擔", "不會扭曲資源配置"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00259', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '關於庇古稅（Pigouviantax）與租稅互動效果（tax-interactioneffect）之敘述，下列何者正確？', '["庇古稅與租稅互動效果無關", "租稅互動效果指的是課徵庇古稅，擴大勞動市場的超額負擔", "租稅互動效果是由課徵消費稅產生的", "租稅互動效果是由課徵土地稅產生的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00260', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '關於柯列特—漢格（Corlett-Hague）法則之敘述，下列何者正確？', '["可以推翻雷姆西（Ramsey）法則的結果", "當有兩商品時，有效率的租稅應對休閒的互補商品課徵較低的稅率", "對休閒的互補財課稅，目的是在間接減少對休閒的需求", "對與休閒有關的商品都課相同的稅率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00261', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '甲與乙二人的效用函數相同，自由選擇在二家公司任職及支出。甲任職的公司提供免費的健身休 閒設施，乙任職的公司則無，而二人的稅後淨報酬相等。若政府未對甲享用免費的健身休閒設施 課稅，主要係參酌下列那一項公平原則？', '["傳統水平公平的定義", "水平公平的規則定義", "水平公平的效用定義", "稅制轉變的公平定義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
